package machotriage

import (
	"encoding/base64"
	"math"
	"math/rand"
	"strings"
	"testing"
)

// The three oracles are the Go toolchain's own debug/macho corpus.
//
// clangRpath: clang-amd64-darwin-exec-with-rpath — a 64-bit x86-64 PIE exec,
// linked against /usr/lib/libSystem.B.dylib, with an LC_RPATH of "/my/rpath".
// gccExec: gcc-amd64-darwin-exec — a 64-bit x86-64 exec, NOT PIE (flags 0x85),
// linked against libgcc_s.1.dylib + libSystem.B.dylib, no rpath, clean imports.
// fatExec: fat-gcc-386-amd64-darwin-exec — a universal binary (i386 + x86-64).
const clangRpath = ""
const gccExec = ""
const fatExec = ""

func decode(t *testing.T, b64 string) *Result {
	t.Helper()
	r, err := Decode(mustB64(t, b64))
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	return r
}

func TestDecode_ClangRpath(t *testing.T) {
	r := decode(t, clangRpath)
	if r.Universal || len(r.Architectures) != 1 {
		t.Fatalf("universal=%v archs=%d, want thin/1", r.Universal, len(r.Architectures))
	}
	a := r.Architectures[0]
	if a.Bits != 64 || a.CPU != "x86-64" {
		t.Errorf("bits=%d cpu=%q, want 64 / x86-64", a.Bits, a.CPU)
	}
	if !strings.HasPrefix(a.Type, "EXECUTE") {
		t.Errorf("type = %q, want EXECUTE", a.Type)
	}
	if !a.PIE {
		t.Errorf("expected PIE")
	}
	if !contains(a.ImportedDylibs, "/usr/lib/libSystem.B.dylib") {
		t.Errorf("dylibs = %v", a.ImportedDylibs)
	}
	if !contains(a.RPaths, "/my/rpath") {
		t.Errorf("rpaths = %v, want /my/rpath", a.RPaths)
	}
	// The RPATH is a dylib-hijack surface → suspicious with that reason.
	if !r.Suspicious || !strings.Contains(strings.Join(r.SuspiciousReasons, " "), "/my/rpath") {
		t.Errorf("expected suspicious-on-rpath: %+v", r.SuspiciousReasons)
	}
}

func TestDecode_GccExec_Clean(t *testing.T) {
	r := decode(t, gccExec)
	a := r.Architectures[0]
	if a.Bits != 64 || a.CPU != "x86-64" {
		t.Errorf("bits=%d cpu=%q", a.Bits, a.CPU)
	}
	if a.PIE {
		t.Errorf("gcc exec is not PIE (flags 0x85), got PIE=true")
	}
	if !contains(a.ImportedDylibs, "/usr/lib/libSystem.B.dylib") || !contains(a.ImportedDylibs, "/usr/lib/libgcc_s.1.dylib") {
		t.Errorf("dylibs = %v", a.ImportedDylibs)
	}
	if len(a.RPaths) != 0 {
		t.Errorf("rpaths = %v, want none", a.RPaths)
	}
	// No rpath, no suspicious imports → clean verdict.
	if r.Suspicious {
		t.Errorf("expected NOT suspicious, got reasons %+v", r.SuspiciousReasons)
	}
	if !strings.Contains(r.Note, "No strong malware indicator") {
		t.Errorf("note = %q", r.Note)
	}
}

func TestDecode_FatUniversal(t *testing.T) {
	r := decode(t, fatExec)
	if !r.Universal {
		t.Fatalf("expected universal=true")
	}
	if len(r.Architectures) != 2 {
		t.Fatalf("archs = %d, want 2 (i386 + x86-64)", len(r.Architectures))
	}
	cpus := []string{r.Architectures[0].CPU, r.Architectures[1].CPU}
	if !contains(cpus, "x86") || !contains(cpus, "x86-64") {
		t.Errorf("fat cpus = %v, want x86 + x86-64", cpus)
	}
	if !strings.Contains(r.Note, "Universal") {
		t.Errorf("note = %q", r.Note)
	}
}

func TestDecode_Errors(t *testing.T) {
	for name, in := range map[string][]byte{
		"empty":     {},
		"not macho": []byte("MZ this is a PE, not Mach-O"),
		"truncated": {0xcf, 0xfa, 0xed, 0xfe, 0x00},
	} {
		if _, err := Decode(in); err == nil {
			t.Errorf("%s: expected error", name)
		}
	}
}

func TestSuspiciousAPI_UnderscoreAndCase(t *testing.T) {
	// Mach-O C symbols carry a leading underscore; the lookup strips it and
	// lower-cases, so both C and CoreFoundation names match.
	for _, sym := range []string{"_ptrace", "_task_for_pid", "_dlopen", "_CGEventTapCreate", "_SecItemCopyMatching", "_NSCreateObjectFileImageFromMemory"} {
		if !suspiciousAPIs[strings.ToLower(strings.TrimPrefix(sym, "_"))] {
			t.Errorf("expected %q to be a suspicious API", sym)
		}
	}
	for _, sym := range []string{"_printf", "_puts", "_malloc"} {
		if suspiciousAPIs[strings.ToLower(strings.TrimPrefix(sym, "_"))] {
			t.Errorf("did not expect %q to be flagged", sym)
		}
	}
}

func TestEntropyExtremes(t *testing.T) {
	zero := make([]byte, 4096)
	if h := shannon(zero); h != 0 {
		t.Errorf("zero entropy = %f, want 0", h)
	}
	uni := make([]byte, 256*16)
	for i := range uni {
		uni[i] = byte(i % 256)
	}
	if h := shannon(uni); h < 7.99 {
		t.Errorf("uniform entropy = %f, want ~8", h)
	}
}

// TestDecode_MutationStress throws a large run of deterministically-mutated
// inputs (byte flips, word/header smashes, growth, truncation) at Decode to
// lock in the no-panic / no-hang property. Decode recovers internally, so a
// regression reintroducing a parser panic surfaces as a failure here; a
// regression reintroducing an unbounded loop trips the suite -timeout. Anchored
// by a one-off 2M-input + per-call-watchdog audit whose slowest Decode was ~12ms.
func TestDecode_MutationStress(t *testing.T) {
	seeds := [][]byte{mustB64(t, fatExec), mustB64(t, clangRpath), mustB64(t, gccExec)}
	rng := rand.New(rand.NewSource(1))
	n := 200000
	if testing.Short() {
		n = 5000
	}
	for i := 0; i < n; i++ {
		s := seeds[rng.Intn(len(seeds))]
		m := make([]byte, len(s))
		copy(m, s)
		for k := 0; k < 1+rng.Intn(8); k++ {
			switch rng.Intn(5) {
			case 0:
				if len(m) > 0 {
					m[rng.Intn(len(m))] = byte(rng.Intn(256))
				}
			case 1:
				if len(m) >= 4 {
					o := rng.Intn(len(m) - 3)
					m[o], m[o+1], m[o+2], m[o+3] = byte(rng.Intn(256)), byte(rng.Intn(256)), byte(rng.Intn(256)), byte(rng.Intn(256))
				}
			case 2:
				if len(m) > 64 {
					o := rng.Intn(64)
					for j := o; j < o+4 && j < len(m); j++ {
						m[j] = 0xff
					}
				}
			case 3:
				m = append(m, make([]byte, rng.Intn(4096))...)
			case 4:
				if len(m) > 100 {
					m = m[:rng.Intn(len(m))]
				}
			}
		}
		_, _ = Decode(m) // must return — no panic, no hang
	}
}

func FuzzDecode(f *testing.F) {
	f.Add(mustB64(f, clangRpath))
	f.Add(mustB64(f, gccExec))
	f.Add(mustB64(f, fatExec))
	f.Add([]byte{0xca, 0xfe, 0xba, 0xbe})
	f.Add([]byte{})
	f.Fuzz(func(_ *testing.T, data []byte) {
		_, _ = Decode(data) // must never panic
	})
}

// --- test helpers ---------------------------------------------------------

func shannon(data []byte) float64 {
	if len(data) == 0 {
		return 0
	}
	var counts [256]int
	for _, b := range data {
		counts[b]++
	}
	n := float64(len(data))
	var h float64
	for _, c := range counts {
		if c == 0 {
			continue
		}
		p := float64(c) / n
		h -= p * math.Log2(p)
	}
	return h
}

func contains(xs []string, s string) bool {
	for _, x := range xs {
		if x == s {
			return true
		}
	}
	return false
}

func mustB64(tb testing.TB, s string) []byte {
	tb.Helper()
	raw, err := base64.StdEncoding.DecodeString(s)
	if err != nil {
		tb.Fatalf("base64: %v", err)
	}
	return raw
}
